import{_ as s,o as a,c as e,ai as t}from"./chunks/framework.C3VoC05s.js";const c=JSON.parse('{"title":"部署","description":"","frontmatter":{},"headers":[],"relativePath":"suan-api/deploy.md","filePath":"suan-api/deploy.md"}'),n={name:"suan-api/deploy.md"};function h(l,i,p,d,r,k){return a(),e("div",null,[...i[0]||(i[0]=[t(`<h1 id="部署" tabindex="-1">部署 <a class="header-anchor" href="#部署" aria-label="Permalink to “部署”">​</a></h1><p>酸 API 同时具备 API 和 MCP 后端的功能。因此，酸 API 不支持 stdio 格式的 MCP 调用。</p><h2 id="部署-suan-api-示例" tabindex="-1">部署 Suan API 示例 <a class="header-anchor" href="#部署-suan-api-示例" aria-label="Permalink to “部署 Suan API 示例”">​</a></h2><p>目前的 Suan API 在设计上即不允许（或者说不适合）公开部署、公共服务，因此你需要自行部署 Suan API 实例。</p><h3 id="使用-uv-部署" tabindex="-1">使用 uv 部署 <a class="header-anchor" href="#使用-uv-部署" aria-label="Permalink to “使用 uv 部署”">​</a></h3><h3 id="使用-docker-部署" tabindex="-1">使用 Docker 部署 <a class="header-anchor" href="#使用-docker-部署" aria-label="Permalink to “使用 Docker 部署”">​</a></h3><h3 id="从源码部署" tabindex="-1">从源码部署 <a class="header-anchor" href="#从源码部署" aria-label="Permalink to “从源码部署”">​</a></h3><div class="warning custom-block"><p class="custom-block-title">性能警告</p><p>直接从 <code>main.py</code> 入口运行可能会导致一些潜在的性能问题，表现为 Suan API 会占用较多的性能，而这可能不是你希望看到的。</p><p>等芒果帆帆再完善完善，然后争取提供其他更方便的部署选项吧~</p></div><p>使用 git 命令从 Mango Gitea 上拉取源代码：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> clone</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://gitea.mangofanfan.cn/SuanDev/NJUPT-Suan-API.git</span></span></code></pre></div><p>这会将项目的源代码克隆到 <code>NJUPT-Suan-API</code> 目录中。</p><p>然后，你需要 uv 和 pnpm 来启动项目，请确保环境中已经安装了它们。</p><p>在 <code>NJUPT-Suan-API</code> 目录下运行：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span></code></pre></div><p>这将会构建 Python 虚拟环境，包括安装 Python 3.13（如果没有）和安装项目使用的依赖。</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> playwright</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> chromium</span></span></code></pre></div><p>这将会安装 chromium 供 playwright 使用。Suan API 通过这个 chromium 来模拟真实用户行为，以及截取课程表图片。</p><p>安装 chromium 可能需要一段<strong>比较长的时间</strong>。大体上这是能够成功的，只是需要一段<strong>比较长的时间</strong>。</p><p>然后（或者同时），在 <code>NJUPT-Suan-API/webui</code> 目录下运行：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pnpm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> build</span></span></code></pre></div><p>这将会安装 WebUI 所使用的依赖，然后构建 WebUI。这一般是很快的。</p><p>现在，回到 <code>NJUPT-Suan-API</code> 目录下，使用以下命令启动项目：</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">uv</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> run</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main.py</span></span></code></pre></div><p>NJUPT Suan API 应当可以正常启动。</p>`,24)])])}const g=s(n,[["render",h]]);export{c as __pageData,g as default};
